        """Checks if the graph contains a cycle using DFS."""
        # 0: white (unvisited), 1: gray (visiting/on current stack), 2: black (finished)
        color = {node: 0 for node in self.nodes}

        def dfs_check(u, path):
            """Recursive helper to check for back edges."""
            color[u] = 1  # Set to visiting (gray)
            path.append(u)

            for edge in self.adj[u]:
                v = edge['neighbor']
                if color[v] == 0:
                    # Unvisited
                    if dfs_check(v, path):
                        return True # Cycle found downstream
                elif color[v] == 1:
                    # Found a back edge to an ancestor (gray) -> Cycle detected
                    return True

            color[u] = 2  # Set to finished (black)
            path.pop()
            return False

        for node in self.nodes:
            if color[node] == 0:
                state_path = [] # Placeholder for the current recursion stack path tracking
                if dfs_check(node, state_path):
                    return True
        return False

