        """Checks if the graph is bipartite using BFS/Coloring."""
        # Colors: 0 (uncolored), 1 (Color A), -1 (Color B)
        color = {node: 0 for node in self.nodes}

        for start_node in self.nodes:
            if color[start_node] == 0:
                queue = deque([(start_node, 1)]) # (node, color)
                color[start_node] = 1

                while queue:
                    u, u_color = queue.popleft()

                    # Potential optimization: Process only through neighbors list instead of iterating over all nodes possible
                    for edge in self.adj[u]:
                        v = edge['neighbor']

